typedef struct jsval_native_microtask_subtle_hkdf_s {
	jsval_native_microtask_t base;
	jsval_off_t promise_off;
	jsval_off_t key_off;
	size_t data_len;
	size_t extra_len;
	uint32_t derived_bit_length;
	uint32_t target_key_bit_length;
	uint32_t target_usages_mask;
	uint8_t operation;
	uint8_t hash_algorithm;
	uint8_t target_algorithm_kind;
	uint8_t target_hash_algorithm;
	uint8_t extractable;
	uint8_t reserved[3];
} jsval_native_microtask_subtle_hkdf_t;

/*
 * Lazy-body source stored inside the region. Carries a vtable pointer,
 * opaque userdata, a content-length hint (SIZE_MAX if unknown), and a
 * `closed` flag so the drain handler can enforce close-once semantics.
 */
typedef struct jsval_native_body_source_s {
	const jsval_body_source_vtable_t *vtable;
	void *userdata;
	size_t content_length_hint;
	uint8_t closed;
	uint8_t reserved[3];
	/* 0 = no parked consumer. Set when a ReadableStream pump
	 * hits PENDING with no buffered chunk; cleared when a wake
	 * (via jsval_body_source_notify) reschedules the pump. */
	jsval_off_t parked_stream_off;
	/* 0 = no parked consumer. Set when a FETCH_BODY_DRAIN
	 * microtask hits PENDING; cleared when a wake re-enqueues
	 * the same task. A given source uses one of the two park
	 * slots at a time (a body is consumed via either the
	 * stream pump or a Body-mixin method, never both). */
	jsval_off_t parked_drain_off;
} jsval_native_body_source_t;

typedef struct jsval_native_microtask_fetch_body_drain_s {
	jsval_native_microtask_t base;
	jsval_off_t promise_off;
	jsval_off_t buffer_off;
	jsval_off_t source_off;
	size_t written_len;
	size_t budget;
	uint8_t consume_mode;
	uint8_t reserved[7];
} jsval_native_microtask_fetch_body_drain_t;

/*
 * ReadableStream state. `state` is 0=readable, 1=closed, 2=errored.
 * `reader_off` is 0 when unlocked. Pending reads form a FIFO of
 * jsval_native_readable_stream_pending_read_t nodes. `pump_scheduled`
 * prevents stacking multiple pump microtasks for the same stream.
 */
typedef enum jsval_readable_stream_state_e {
	JSVAL_READABLE_STREAM_STATE_READABLE = 0,
	JSVAL_READABLE_STREAM_STATE_CLOSED = 1,
	JSVAL_READABLE_STREAM_STATE_ERRORED = 2
} jsval_readable_stream_state_t;

typedef struct jsval_native_readable_stream_s {
	jsval_off_t source_off;
	jsval_off_t reader_off;
	jsval_off_t pending_reads_head;
	jsval_off_t pending_reads_tail;
	jsval_t error_reason;
	uint8_t state;
	uint8_t pump_scheduled;
	uint8_t reserved[6];
} jsval_native_readable_stream_t;

typedef struct jsval_native_readable_stream_reader_s {
	jsval_off_t stream_off;
	uint8_t reserved[4];
} jsval_native_readable_stream_reader_t;

typedef struct jsval_native_readable_stream_pending_read_s {
	jsval_off_t next_off;
	jsval_off_t promise_off;
} jsval_native_readable_stream_pending_read_t;

typedef struct jsval_native_microtask_readable_stream_pump_s {
	jsval_native_microtask_t base;
	jsval_off_t stream_off;
} jsval_native_microtask_readable_stream_pump_t;

/*
 * In-memory byte source userdata for jsval_readable_stream_new_from_bytes.
 * Allocated immediately after a jsval_native_body_source_t in the region;
 * the `len` bytes follow the struct.
 */
typedef struct jsval_native_readable_stream_bytes_source_s {
	size_t len;
	size_t cursor;
} jsval_native_readable_stream_bytes_source_t;

/*
 * Outbound-fetch microtask. Holds the pending Promise plus the transport
 * vtable + opaque state allocated by the transport's begin callback.
 * Pointers to the vtable and state are embedder-owned (not region-owned);
 * they survive across region_ptr dereferences because they live outside
 * the region. The embedder is responsible for draining to completion
 * before rewinding the region.
 */
typedef struct jsval_native_microtask_fetch_request_s {
	jsval_native_microtask_t base;
	jsval_off_t promise_off;
	void *transport_state;
	const jsval_fetch_transport_t *transport_vtable;
	void *transport_userdata;
} jsval_native_microtask_fetch_request_t;

/*
 * External-driver fetch waitlist entry — a (Request, Promise) pair
 * parked until the embedder's outbound HTTP/1.1 driver picks it up.
 * Unlike the FETCH_REQUEST microtask, the waitlist does NOT live on
 * the microtask queue — it is a separate FIFO rooted in the region
 * so the microtask drain never re-polls it. The embedder pops
 * entries via jsval_fetch_waitlist_pop and resolves their promises
 * from its own coroutine body.
 */
typedef struct jsval_native_fetch_waitlist_entry_s {
	jsval_off_t next_off;
	jsval_off_t request_off;
	jsval_off_t promise_off;
} jsval_native_fetch_waitlist_entry_t;

