int
jsval_crypto_subtle(jsval_region_t *region, jsval_t crypto_value,
		jsval_t *value_ptr)
{
	jsval_native_crypto_t *native;
	jsval_t subtle_value;

	if (value_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	native = jsval_native_crypto(region, crypto_value);
	if (native == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (native->subtle_value.kind == JSVAL_KIND_SUBTLE_CRYPTO
			&& native->subtle_value.repr == JSVAL_REPR_NATIVE) {
		*value_ptr = native->subtle_value;
		return 0;
	}
	if (jsval_subtle_crypto_new(region, &subtle_value) < 0) {
		return -1;
	}
	native->subtle_value = subtle_value;
	*value_ptr = subtle_value;
	return 0;
}

static int
jsval_webcrypto_error_set(jsval_webcrypto_error_t *error,
		const char *name, const char *message)
{
	if (error != NULL) {
		error->name = name;
		error->message = message;
	}
	return -1;
}

static int
jsval_subtle_crypto_reject(jsval_region_t *region, jsval_t promise_value,
		const char *name, const char *message)
{
	jsval_t reason;

	if (jsval_dom_exception_new_utf8(region, name, message, &reason) < 0) {
		return -1;
	}
	return jsval_promise_reject(region, promise_value, reason);
}

