static int
jsval_string_eq_ascii(jsval_region_t *region, jsval_t value,
		const char *expected)
{
	uint8_t buf[32];
	size_t len = 0;
	size_t expected_len;

	if (region == NULL || expected == NULL || value.kind != JSVAL_KIND_STRING) {
		errno = EINVAL;
		return -1;
	}
	expected_len = strlen(expected);
	if (expected_len > sizeof(buf)) {
		errno = EOVERFLOW;
		return -1;
	}
	if (jsval_string_copy_utf8(region, value, NULL, 0, &len) < 0) {
		return -1;
	}
	if (len != expected_len) {
		return 0;
	}
	if (len > 0 && jsval_string_copy_utf8(region, value, buf, len, NULL) < 0) {
		return -1;
	}
	return memcmp(buf, expected, len) == 0;
}

static int
jsval_subtle_crypto_read_enforce_range_u32(jsval_region_t *region,
		jsval_t value, uint32_t *out_ptr, jsval_webcrypto_error_t *error,
		const char *message)
{
	double number;

	if (out_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (jsval_to_number(region, value, &number) < 0) {
		return jsval_webcrypto_error_set(error, "TypeError", message);
	}
	if (!isfinite(number) || number < 0.0 || number > 4294967295.0
			|| (double)(uint32_t)number != number) {
		return jsval_webcrypto_error_set(error, "TypeError", message);
	}
	*out_ptr = (uint32_t)number;
	return 0;
}

static int
jsval_subtle_crypto_parse_format(jsval_region_t *region, jsval_t format_value,
		jsval_subtle_crypto_key_format_t *format_ptr,
		jsval_webcrypto_error_t *error)
{
	if (format_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (format_value.kind != JSVAL_KIND_STRING) {
		return jsval_webcrypto_error_set(error, "TypeError",
				"expected key format string");
	}
	if (jsval_string_eq_ascii(region, format_value, "raw") > 0) {
		*format_ptr = JSVAL_SUBTLE_CRYPTO_KEY_FORMAT_RAW;
		return 0;
	}
	if (jsval_string_eq_ascii(region, format_value, "jwk") > 0) {
		*format_ptr = JSVAL_SUBTLE_CRYPTO_KEY_FORMAT_JWK;
		return 0;
	}
	if (jsval_string_eq_ascii(region, format_value, "spki") > 0) {
		*format_ptr = JSVAL_SUBTLE_CRYPTO_KEY_FORMAT_SPKI;
		return 0;
	}
	if (jsval_string_eq_ascii(region, format_value, "pkcs8") > 0) {
		*format_ptr = JSVAL_SUBTLE_CRYPTO_KEY_FORMAT_PKCS8;
		return 0;
	}
	return jsval_webcrypto_error_set(error, "NotSupportedError",
			"unsupported key format");
}

static int
jsval_subtle_crypto_parse_usages(jsval_region_t *region, jsval_t usages_value,
		uint32_t allowed_mask, int require_non_empty, uint32_t *mask_ptr,
		jsval_webcrypto_error_t *error)
{
	size_t len;
	size_t i;
	uint32_t mask = 0;

	if (mask_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (usages_value.kind != JSVAL_KIND_ARRAY) {
		return jsval_webcrypto_error_set(error, "TypeError",
				"expected key usages array");
	}
	len = jsval_array_length(region, usages_value);
	if (require_non_empty && len == 0) {
		return jsval_webcrypto_error_set(error, "SyntaxError",
				"expected non-empty key usages");
	}
	for (i = 0; i < len; i++) {
		jsval_t value;
		int eq;

		if (jsval_array_get(region, usages_value, i, &value) < 0) {
			return -1;
		}
		if (value.kind != JSVAL_KIND_STRING) {
			return jsval_webcrypto_error_set(error, "TypeError",
					"expected key usage string");
		}
		eq = jsval_string_eq_ascii(region, value, "sign");
		if (eq < 0) {
			return -1;
		}
		if (eq > 0) {
			mask |= JSVAL_CRYPTO_KEY_USAGE_SIGN;
			continue;
		}
		eq = jsval_string_eq_ascii(region, value, "verify");
		if (eq < 0) {
			return -1;
		}
		if (eq > 0) {
			mask |= JSVAL_CRYPTO_KEY_USAGE_VERIFY;
			continue;
		}
		eq = jsval_string_eq_ascii(region, value, "encrypt");
		if (eq < 0) {
			return -1;
		}
		if (eq > 0) {
			mask |= JSVAL_CRYPTO_KEY_USAGE_ENCRYPT;
			continue;
		}
		eq = jsval_string_eq_ascii(region, value, "decrypt");
		if (eq < 0) {
			return -1;
		}
		if (eq > 0) {
			mask |= JSVAL_CRYPTO_KEY_USAGE_DECRYPT;
			continue;
		}
		eq = jsval_string_eq_ascii(region, value, "deriveBits");
		if (eq < 0) {
			return -1;
		}
		if (eq > 0) {
			mask |= JSVAL_CRYPTO_KEY_USAGE_DERIVE_BITS;
			continue;
		}
		eq = jsval_string_eq_ascii(region, value, "deriveKey");
		if (eq < 0) {
			return -1;
		}
		if (eq > 0) {
			mask |= JSVAL_CRYPTO_KEY_USAGE_DERIVE_KEY;
			continue;
		}
		eq = jsval_string_eq_ascii(region, value, "wrapKey");
		if (eq < 0) {
			return -1;
		}
		if (eq > 0) {
			mask |= JSVAL_CRYPTO_KEY_USAGE_WRAP_KEY;
			continue;
		}
		eq = jsval_string_eq_ascii(region, value, "unwrapKey");
		if (eq < 0) {
			return -1;
		}
		if (eq > 0) {
			mask |= JSVAL_CRYPTO_KEY_USAGE_UNWRAP_KEY;
			continue;
		}
		return jsval_webcrypto_error_set(error, "SyntaxError",
				"unsupported key usage");
	}
	if ((mask & ~allowed_mask) != 0) {
		return jsval_webcrypto_error_set(error, "SyntaxError",
				"unsupported key usage");
	}
	if (require_non_empty && mask == 0) {
		return jsval_webcrypto_error_set(error, "SyntaxError",
				"expected non-empty key usages");
	}
	*mask_ptr = mask;
	return 0;
}

static int
jsval_base64url_value(uint8_t ch)
{
	if (ch >= 'A' && ch <= 'Z') {
		return ch - 'A';
	}
	if (ch >= 'a' && ch <= 'z') {
		return ch - 'a' + 26;
	}
	if (ch >= '0' && ch <= '9') {
		return ch - '0' + 52;
	}
	if (ch == '-') {
		return 62;
	}
	if (ch == '_') {
		return 63;
	}
	return -1;
}

static int
jsval_base64url_raw_encode(const uint8_t *input, size_t input_len, uint8_t *buf,
		size_t cap, size_t *len_ptr)
{
	static const uint8_t alphabet[] =
		"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_";
	size_t out_len = (input_len / 3) * 4;
	size_t i;
	size_t out = 0;

	switch (input_len % 3) {
	case 1:
		out_len += 2;
		break;
	case 2:
		out_len += 3;
		break;
	default:
		break;
	}
	if (len_ptr != NULL) {
		*len_ptr = out_len;
	}
	if (buf == NULL) {
		return 0;
	}
	if (cap < out_len) {
		errno = ENOBUFS;
		return -1;
	}
	for (i = 0; i + 2 < input_len; i += 3) {
		uint32_t word = ((uint32_t)input[i] << 16)
			| ((uint32_t)input[i + 1] << 8) | input[i + 2];

		buf[out++] = alphabet[(word >> 18) & 0x3f];
		buf[out++] = alphabet[(word >> 12) & 0x3f];
		buf[out++] = alphabet[(word >> 6) & 0x3f];
		buf[out++] = alphabet[word & 0x3f];
	}
	if (input_len - i == 1) {
		uint32_t word = (uint32_t)input[i] << 16;

		buf[out++] = alphabet[(word >> 18) & 0x3f];
		buf[out++] = alphabet[(word >> 12) & 0x3f];
	} else if (input_len - i == 2) {
		uint32_t word = ((uint32_t)input[i] << 16)
			| ((uint32_t)input[i + 1] << 8);

		buf[out++] = alphabet[(word >> 18) & 0x3f];
		buf[out++] = alphabet[(word >> 12) & 0x3f];
		buf[out++] = alphabet[(word >> 6) & 0x3f];
	}
	return 0;
}

static int
jsval_base64url_raw_decode(const uint8_t *input, size_t input_len, uint8_t *buf,
		size_t cap, size_t *len_ptr)
{
	size_t out_len;
	size_t cursor = 0;
	size_t out = 0;

	if ((input == NULL && input_len > 0) || (buf == NULL && cap > 0)) {
		errno = EINVAL;
		return -1;
	}
	if ((input_len % 4) == 1) {
		errno = EINVAL;
		return -1;
	}
	out_len = (input_len / 4) * 3;
	if ((input_len % 4) == 2) {
		out_len += 1;
	} else if ((input_len % 4) == 3) {
		out_len += 2;
	}
	if (len_ptr != NULL) {
		*len_ptr = out_len;
	}
	if (buf == NULL) {
		return 0;
	}
	if (cap < out_len) {
		errno = ENOBUFS;
		return -1;
	}
	while (cursor + 4 <= input_len) {
		int a = jsval_base64url_value(input[cursor]);
		int b = jsval_base64url_value(input[cursor + 1]);
		int c = jsval_base64url_value(input[cursor + 2]);
		int d = jsval_base64url_value(input[cursor + 3]);
		uint32_t word;

		if (a < 0 || b < 0 || c < 0 || d < 0) {
			errno = EINVAL;
			return -1;
		}
		word = ((uint32_t)a << 18) | ((uint32_t)b << 12)
			| ((uint32_t)c << 6) | (uint32_t)d;
		buf[out++] = (uint8_t)((word >> 16) & 0xff);
		buf[out++] = (uint8_t)((word >> 8) & 0xff);
		buf[out++] = (uint8_t)(word & 0xff);
		cursor += 4;
	}
	if (input_len - cursor == 2) {
		int a = jsval_base64url_value(input[cursor]);
		int b = jsval_base64url_value(input[cursor + 1]);
		uint32_t word;

		if (a < 0 || b < 0) {
			errno = EINVAL;
			return -1;
		}
		word = ((uint32_t)a << 18) | ((uint32_t)b << 12);
		buf[out++] = (uint8_t)((word >> 16) & 0xff);
	} else if (input_len - cursor == 3) {
		int a = jsval_base64url_value(input[cursor]);
		int b = jsval_base64url_value(input[cursor + 1]);
		int c = jsval_base64url_value(input[cursor + 2]);
		uint32_t word;

		if (a < 0 || b < 0 || c < 0) {
			errno = EINVAL;
			return -1;
		}
		word = ((uint32_t)a << 18) | ((uint32_t)b << 12)
			| ((uint32_t)c << 6);
		buf[out++] = (uint8_t)((word >> 16) & 0xff);
		buf[out++] = (uint8_t)((word >> 8) & 0xff);
	}
	return 0;
}

static int
jsval_base64_std_value(uint8_t ch)
{
	if (ch >= 'A' && ch <= 'Z') {
		return ch - 'A';
	}
	if (ch >= 'a' && ch <= 'z') {
		return ch - 'a' + 26;
	}
	if (ch >= '0' && ch <= '9') {
		return ch - '0' + 52;
	}
	if (ch == '+') {
		return 62;
	}
	if (ch == '/') {
		return 63;
	}
	return -1;
}

static int
jsval_base64_std_encode(const uint8_t *input, size_t input_len, uint8_t *buf,
		size_t cap, size_t *len_ptr)
{
	static const uint8_t alphabet[] =
		"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
	size_t out_len = ((input_len + 2) / 3) * 4;
	size_t i;
	size_t out = 0;

	if (len_ptr != NULL) {
		*len_ptr = out_len;
	}
	if (buf == NULL) {
		return 0;
	}
	if (cap < out_len) {
		errno = ENOBUFS;
		return -1;
	}
	for (i = 0; i + 2 < input_len; i += 3) {
		uint32_t word = ((uint32_t)input[i] << 16)
			| ((uint32_t)input[i + 1] << 8) | input[i + 2];

		buf[out++] = alphabet[(word >> 18) & 0x3f];
		buf[out++] = alphabet[(word >> 12) & 0x3f];
		buf[out++] = alphabet[(word >> 6) & 0x3f];
		buf[out++] = alphabet[word & 0x3f];
	}
	if (input_len - i == 1) {
		uint32_t word = (uint32_t)input[i] << 16;

		buf[out++] = alphabet[(word >> 18) & 0x3f];
		buf[out++] = alphabet[(word >> 12) & 0x3f];
		buf[out++] = (uint8_t)'=';
		buf[out++] = (uint8_t)'=';
	} else if (input_len - i == 2) {
		uint32_t word = ((uint32_t)input[i] << 16)
			| ((uint32_t)input[i + 1] << 8);

		buf[out++] = alphabet[(word >> 18) & 0x3f];
		buf[out++] = alphabet[(word >> 12) & 0x3f];
		buf[out++] = alphabet[(word >> 6) & 0x3f];
		buf[out++] = (uint8_t)'=';
	}
	return 0;
}

static int
jsval_base64_std_decode(const uint8_t *input, size_t input_len, uint8_t *buf,
		size_t cap, size_t *len_ptr)
{
	size_t effective_len = input_len;
	size_t pad_count = 0;
	size_t out_len;
	size_t cursor = 0;
	size_t out = 0;
	size_t whole_groups;
	size_t trailing;

	if ((input == NULL && input_len > 0) || (buf == NULL && cap > 0)) {
		errno = EINVAL;
		return -1;
	}
	/* Standard base64 is always padded to a multiple of 4. Accept
	 * trailing "=" (one or two) and drop them from the effective
	 * length before decoding. */
	if (input_len > 0 && (input_len % 4) != 0) {
		errno = EINVAL;
		return -1;
	}
	while (effective_len > 0 && input[effective_len - 1] == '=' &&
			pad_count < 2) {
		effective_len--;
		pad_count++;
	}
	if (effective_len > 0 && input[effective_len - 1] == '=') {
		/* More than two '=' trailing is never valid. */
		errno = EINVAL;
		return -1;
	}
	if ((effective_len % 4) == 1) {
		errno = EINVAL;
		return -1;
	}
	whole_groups = effective_len / 4;
	trailing = effective_len % 4;
	out_len = whole_groups * 3;
	if (trailing == 2) {
		out_len += 1;
	} else if (trailing == 3) {
		out_len += 2;
	}
	if (len_ptr != NULL) {
		*len_ptr = out_len;
	}
	if (buf == NULL) {
		return 0;
	}
	if (cap < out_len) {
		errno = ENOBUFS;
		return -1;
	}
	while (cursor + 4 <= effective_len) {
		int a = jsval_base64_std_value(input[cursor]);
		int b = jsval_base64_std_value(input[cursor + 1]);
		int c = jsval_base64_std_value(input[cursor + 2]);
		int d = jsval_base64_std_value(input[cursor + 3]);
		uint32_t word;

		if (a < 0 || b < 0 || c < 0 || d < 0) {
			errno = EINVAL;
			return -1;
		}
		word = ((uint32_t)a << 18) | ((uint32_t)b << 12)
			| ((uint32_t)c << 6) | (uint32_t)d;
		buf[out++] = (uint8_t)((word >> 16) & 0xff);
		buf[out++] = (uint8_t)((word >> 8) & 0xff);
		buf[out++] = (uint8_t)(word & 0xff);
		cursor += 4;
	}
	if (trailing == 2) {
		int a = jsval_base64_std_value(input[cursor]);
		int b = jsval_base64_std_value(input[cursor + 1]);
		uint32_t word;

		if (a < 0 || b < 0) {
			errno = EINVAL;
			return -1;
		}
		word = ((uint32_t)a << 18) | ((uint32_t)b << 12);
		buf[out++] = (uint8_t)((word >> 16) & 0xff);
	} else if (trailing == 3) {
		int a = jsval_base64_std_value(input[cursor]);
		int b = jsval_base64_std_value(input[cursor + 1]);
		int c = jsval_base64_std_value(input[cursor + 2]);
		uint32_t word;

		if (a < 0 || b < 0 || c < 0) {
			errno = EINVAL;
			return -1;
		}
		word = ((uint32_t)a << 18) | ((uint32_t)b << 12)
			| ((uint32_t)c << 6);
		buf[out++] = (uint8_t)((word >> 16) & 0xff);
		buf[out++] = (uint8_t)((word >> 8) & 0xff);
	}
	return 0;
}

static int
jsval_subtle_crypto_mask_unused_key_bits(uint8_t *bytes, size_t byte_len,
		uint32_t bit_len)
{
	uint32_t remainder;

	if ((bytes == NULL && byte_len > 0) || (bit_len == 0 && byte_len > 0)) {
		errno = EINVAL;
		return -1;
	}
	remainder = bit_len & 7u;
	if (byte_len > 0 && remainder != 0) {
		uint8_t mask = (uint8_t)(0xffu << (8u - remainder));
		bytes[byte_len - 1] &= mask;
	}
	return 0;
}

static int
jsval_subtle_crypto_hash_object_new(jsval_region_t *region,
		jscrypto_digest_algorithm_t algorithm, jsval_t *value_ptr)
{
	const char *name = jsval_subtle_crypto_digest_name(algorithm);
	jsval_t object;
	jsval_t name_value;

	if (name == NULL || value_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (jsval_object_new(region, 1, &object) < 0
			|| jsval_string_new_utf8(region, (const uint8_t *)name,
				strlen(name), &name_value) < 0
			|| jsval_object_set_utf8(region, object, (const uint8_t *)"name", 4,
				name_value) < 0) {
		return -1;
	}
	*value_ptr = object;
	return 0;
}

static int
jsval_subtle_crypto_hmac_algorithm_object_new(jsval_region_t *region,
		jscrypto_digest_algorithm_t hash_algorithm, uint32_t bit_length,
		jsval_t *value_ptr)
{
	jsval_t object;
	jsval_t name_value;
	jsval_t hash_value;

	if (value_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (jsval_object_new(region, 3, &object) < 0
			|| jsval_string_new_utf8(region, (const uint8_t *)"HMAC", 4,
				&name_value) < 0
			|| jsval_subtle_crypto_hash_object_new(region, hash_algorithm,
				&hash_value) < 0
			|| jsval_object_set_utf8(region, object, (const uint8_t *)"name", 4,
				name_value) < 0
			|| jsval_object_set_utf8(region, object, (const uint8_t *)"hash", 4,
				hash_value) < 0
			|| jsval_object_set_utf8(region, object, (const uint8_t *)"length", 6,
				jsval_number((double)bit_length)) < 0) {
		return -1;
	}
	*value_ptr = object;
	return 0;
}

static int
jsval_subtle_crypto_usages_array_new(jsval_region_t *region,
		uint32_t usages_mask, jsval_t *value_ptr)
{
	jsval_t array;
	size_t cap = 0;
	jsval_t value;

	if (value_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_SIGN) {
		cap++;
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_VERIFY) {
		cap++;
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_ENCRYPT) {
		cap++;
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_DECRYPT) {
		cap++;
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_DERIVE_BITS) {
		cap++;
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_DERIVE_KEY) {
		cap++;
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_WRAP_KEY) {
		cap++;
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_UNWRAP_KEY) {
		cap++;
	}
	if (jsval_array_new(region, cap, &array) < 0) {
		return -1;
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_SIGN) {
		if (jsval_string_new_utf8(region, (const uint8_t *)"sign", 4, &value)
				< 0
				|| jsval_array_push(region, array, value) < 0) {
			return -1;
		}
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_VERIFY) {
		if (jsval_string_new_utf8(region, (const uint8_t *)"verify", 6, &value)
				< 0
				|| jsval_array_push(region, array, value) < 0) {
			return -1;
		}
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_ENCRYPT) {
		if (jsval_string_new_utf8(region, (const uint8_t *)"encrypt", 7,
				&value) < 0
				|| jsval_array_push(region, array, value) < 0) {
			return -1;
		}
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_DECRYPT) {
		if (jsval_string_new_utf8(region, (const uint8_t *)"decrypt", 7,
				&value) < 0
				|| jsval_array_push(region, array, value) < 0) {
			return -1;
		}
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_DERIVE_BITS) {
		if (jsval_string_new_utf8(region, (const uint8_t *)"deriveBits", 10,
				&value) < 0
				|| jsval_array_push(region, array, value) < 0) {
			return -1;
		}
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_DERIVE_KEY) {
		if (jsval_string_new_utf8(region, (const uint8_t *)"deriveKey", 9,
				&value) < 0
				|| jsval_array_push(region, array, value) < 0) {
			return -1;
		}
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_WRAP_KEY) {
		if (jsval_string_new_utf8(region, (const uint8_t *)"wrapKey", 7,
				&value) < 0
				|| jsval_array_push(region, array, value) < 0) {
			return -1;
		}
	}
	if (usages_mask & JSVAL_CRYPTO_KEY_USAGE_UNWRAP_KEY) {
		if (jsval_string_new_utf8(region, (const uint8_t *)"unwrapKey", 9,
				&value) < 0
				|| jsval_array_push(region, array, value) < 0) {
			return -1;
		}
	}
	*value_ptr = array;
	return 0;
}

/*
 * Shared JWK export builder for oct (symmetric) keys. The five existing
 * per-algorithm `_build_export_jwk` helpers all have the same body
 * except for the alg lookup; this helper takes the pre-computed alg
 * string (the caller picks it from the algorithm's own `_jwk_alg`
 * function) and builds the final JWK object `{kty, k, alg, key_ops,
 * ext}`.
 */
static int
jsval_subtle_crypto_build_oct_jwk_export(jsval_region_t *region,
		jsval_native_crypto_key_t *key, const char *alg_name,
		jsval_t *value_ptr)
{
	jsval_t object;
	jsval_t value;
	jsval_t key_ops;
	uint8_t b64[256];
	size_t key_len;
	size_t b64_len = 0;
	const uint8_t *key_bytes;

	if (region == NULL || key == NULL || alg_name == NULL
			|| value_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	key_bytes = jsval_native_crypto_key_bytes(region, key);
	key_len = key->key_byte_length;
	if (key_bytes == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (jsval_base64url_raw_encode(key_bytes, key_len, NULL, 0, &b64_len) < 0) {
		return -1;
	}
	if (b64_len > sizeof(b64)) {
		errno = EOVERFLOW;
		return -1;
	}
	if (jsval_base64url_raw_encode(key_bytes, key_len, b64, sizeof(b64), NULL) < 0) {
		return -1;
	}
	if (jsval_object_new(region, 5, &object) < 0) {
		return -1;
	}
	if (jsval_string_new_utf8(region, (const uint8_t *)"oct", 3, &value) < 0
			|| jsval_object_set_utf8(region, object, (const uint8_t *)"kty", 3,
				value) < 0) {
		return -1;
	}
	if (jsval_string_new_utf8(region, b64, b64_len, &value) < 0
			|| jsval_object_set_utf8(region, object, (const uint8_t *)"k", 1,
				value) < 0) {
		return -1;
	}
	if (jsval_string_new_utf8(region, (const uint8_t *)alg_name,
			strlen(alg_name), &value) < 0
			|| jsval_object_set_utf8(region, object, (const uint8_t *)"alg", 3,
				value) < 0) {
		return -1;
	}
	if (jsval_subtle_crypto_usages_array_new(region, key->usages_mask,
			&key_ops) < 0
			|| jsval_object_set_utf8(region, object,
				(const uint8_t *)"key_ops", 7, key_ops) < 0) {
		return -1;
	}
	if (jsval_object_set_utf8(region, object, (const uint8_t *)"ext", 3,
			jsval_bool(key->extractable ? 1 : 0)) < 0) {
		return -1;
	}
	*value_ptr = object;
	return 0;
}

static int jsval_subtle_crypto_aes_key_length_valid(uint32_t key_bit_length);

/*
 * Shared secret-key validator. Replaces the five near-identical
 * `_{algo}_key_validate` helpers. `require_aes_length` enables the
 * AES 128/192/256 bit-length check; HMAC and other non-AES algorithms
 * should pass 0 and the helper only checks for non-zero key_bit_length.
 * The `expected_label` string is baked into the InvalidAccessError
 * message.
 */
static int
jsval_subtle_crypto_validate_secret_key(jsval_region_t *region,
		jsval_t key_value, jsval_crypto_algorithm_kind_t expected_kind,
		int require_aes_length, uint32_t required_usages,
		int require_extractable, const char *expected_label,
		jsval_native_crypto_key_t **native_ptr,
		jsval_webcrypto_error_t *error)
{
	jsval_native_crypto_key_t *native;

	native = jsval_native_crypto_key(region, key_value);
	if (native == NULL) {
		return jsval_webcrypto_error_set(error, "TypeError",
				"expected CryptoKey value");
	}
	if ((jsval_crypto_key_type_t)native->type != JSVAL_CRYPTO_KEY_TYPE_SECRET
			|| (jsval_crypto_algorithm_kind_t)native->algorithm_kind
				!= expected_kind
			|| native->key_byte_length == 0
			|| jsval_native_crypto_key_bytes(region, native) == NULL) {
		return jsval_webcrypto_error_set(error, "InvalidAccessError",
				expected_label);
	}
	if (require_aes_length
			? !jsval_subtle_crypto_aes_key_length_valid(native->key_bit_length)
			: native->key_bit_length == 0) {
		return jsval_webcrypto_error_set(error, "InvalidAccessError",
				expected_label);
	}
	if (required_usages != 0
			&& (native->usages_mask & required_usages) != required_usages) {
		return jsval_webcrypto_error_set(error, "InvalidAccessError",
				"key does not support requested usage");
	}
	if (require_extractable && !native->extractable) {
		return jsval_webcrypto_error_set(error, "InvalidAccessError",
				"key is not extractable");
	}
	if (native_ptr != NULL) {
		*native_ptr = native;
	}
	return 0;
}

/*
 * Shared JWK `key_ops` array parser. Replaces the five near-identical
 * inline loops in `jsval_subtle_crypto_import_key` JWK branches. Takes
 * an allowed-mask parameter (which operations are valid for this
 * algorithm) and the declared usages_mask (the `keyUsages` argument),
 * and confirms that declared usages are a subset of the present mask.
 * Rejects with DataError on any unknown/disallowed usage string.
 */
static int
jsval_subtle_crypto_parse_jwk_oct_key_ops(jsval_region_t *region,
		jsval_t key_ops_value, uint32_t allowed_mask,
		uint32_t declared_usages_mask, jsval_webcrypto_error_t *error)
{
	size_t i;
	size_t len;
	uint32_t present_mask = 0;

	if (key_ops_value.kind != JSVAL_KIND_ARRAY) {
		return jsval_webcrypto_error_set(error, "DataError",
				"invalid JWK key_ops");
	}
	len = jsval_array_length(region, key_ops_value);
	for (i = 0; i < len; i++) {
		jsval_t item;
		uint32_t bit = 0;

		if (jsval_array_get(region, key_ops_value, i, &item) < 0) {
			return -1;
		}
		if (item.kind != JSVAL_KIND_STRING) {
			return jsval_webcrypto_error_set(error, "DataError",
					"invalid JWK key_ops");
		}
		if (jsval_string_eq_ascii(region, item, "sign") > 0) {
			bit = JSVAL_CRYPTO_KEY_USAGE_SIGN;
		} else if (jsval_string_eq_ascii(region, item, "verify") > 0) {
			bit = JSVAL_CRYPTO_KEY_USAGE_VERIFY;
		} else if (jsval_string_eq_ascii(region, item, "encrypt") > 0) {
			bit = JSVAL_CRYPTO_KEY_USAGE_ENCRYPT;
		} else if (jsval_string_eq_ascii(region, item, "decrypt") > 0) {
			bit = JSVAL_CRYPTO_KEY_USAGE_DECRYPT;
		} else if (jsval_string_eq_ascii(region, item, "wrapKey") > 0) {
			bit = JSVAL_CRYPTO_KEY_USAGE_WRAP_KEY;
		} else if (jsval_string_eq_ascii(region, item, "unwrapKey") > 0) {
			bit = JSVAL_CRYPTO_KEY_USAGE_UNWRAP_KEY;
		} else {
			return jsval_webcrypto_error_set(error, "DataError",
					"invalid JWK key_ops");
		}
		if ((bit & allowed_mask) == 0) {
			return jsval_webcrypto_error_set(error, "DataError",
					"invalid JWK key_ops");
		}
		present_mask |= bit;
	}
	if ((declared_usages_mask & ~present_mask) != 0) {
		return jsval_webcrypto_error_set(error, "DataError",
				"invalid JWK key_ops");
	}
	return 0;
}

