static int
jsval_subtle_crypto_run_aes_ctr(jsval_region_t *region,
		jsval_native_microtask_subtle_aes_ctr_t *task)
{
	static const char operation_error_name[] = "OperationError";
	static const char operation_error_message[] = "AES-CTR operation failed";
	jsval_t promise_value;
	jsval_t result;
	jsval_t reason;
	jsval_native_crypto_key_t *key;
	jsval_webcrypto_error_t error;

	if (region == NULL || task == NULL) {
		errno = EINVAL;
		return -1;
	}
	promise_value = jsval_promise_value(task->promise_off);
	switch ((jsval_subtle_aes_ctr_task_op_t)task->operation) {
	case JSVAL_SUBTLE_AES_CTR_TASK_GENERATE:
	{
		uint8_t *bytes = jsval_native_microtask_subtle_aes_ctr_data(task);

		if (jscrypto_random_bytes(bytes, task->data_len) < 0
				|| jsval_subtle_crypto_aes_ctr_algorithm_object_new(region,
					task->key_bit_length, &result) < 0
				|| jsval_crypto_key_new_internal(region,
					JSVAL_CRYPTO_KEY_TYPE_SECRET, task->extractable != 0,
					result, task->usages_mask,
					JSVAL_CRYPTO_ALGORITHM_AES_CTR, 0,
					task->key_bit_length, bytes, task->data_len,
					&result) < 0) {
			if (jsval_dom_exception_new_utf8(region, operation_error_name,
					operation_error_message, &reason) < 0) {
				return -1;
			}
			return jsval_promise_reject(region, promise_value, reason);
		}
		return jsval_promise_resolve(region, promise_value, result);
	}
	case JSVAL_SUBTLE_AES_CTR_TASK_IMPORT:
		if (jsval_subtle_crypto_aes_ctr_algorithm_object_new(region,
				task->key_bit_length, &result) < 0
				|| jsval_crypto_key_new_internal(region,
					JSVAL_CRYPTO_KEY_TYPE_SECRET, task->extractable != 0,
					result, task->usages_mask,
					JSVAL_CRYPTO_ALGORITHM_AES_CTR, 0,
					task->key_bit_length,
					jsval_native_microtask_subtle_aes_ctr_data(task),
					task->data_len, &result) < 0) {
			if (jsval_dom_exception_new_utf8(region, operation_error_name,
					operation_error_message, &reason) < 0) {
				return -1;
			}
			return jsval_promise_reject(region, promise_value, reason);
		}
		return jsval_promise_resolve(region, promise_value, result);
	case JSVAL_SUBTLE_AES_CTR_TASK_EXPORT:
		error.name = NULL;
		error.message = NULL;
		if (jsval_subtle_crypto_aes_ctr_key_validate(region,
				jsval_crypto_key_value(task->key_off), 0, 1, &key, &error) < 0) {
			return jsval_subtle_crypto_reject(region, promise_value,
					error.name, error.message);
		}
		if ((jsval_subtle_crypto_key_format_t)task->format
				== JSVAL_SUBTLE_CRYPTO_KEY_FORMAT_RAW) {
			jsval_native_array_buffer_t *buffer;
			uint8_t *out;

			if (jsval_array_buffer_new(region, key->key_byte_length, &result) < 0) {
				return -1;
			}
			buffer = jsval_native_array_buffer(region, result);
			if (buffer == NULL) {
				errno = EINVAL;
				return -1;
			}
			out = jsval_native_array_buffer_bytes(buffer);
			memcpy(out, jsval_native_crypto_key_bytes(region, key),
					key->key_byte_length);
			return jsval_promise_resolve(region, promise_value, result);
		}
		if (jsval_subtle_crypto_aes_ctr_build_export_jwk(region, key,
				&result) < 0) {
			if (jsval_dom_exception_new_utf8(region, operation_error_name,
					operation_error_message, &reason) < 0) {
				return -1;
			}
			return jsval_promise_reject(region, promise_value, reason);
		}
		return jsval_promise_resolve(region, promise_value, result);
	case JSVAL_SUBTLE_AES_CTR_TASK_ENCRYPT:
	case JSVAL_SUBTLE_AES_CTR_TASK_DECRYPT:
	{
		uint32_t required = (jsval_subtle_aes_ctr_task_op_t)task->operation
			== JSVAL_SUBTLE_AES_CTR_TASK_ENCRYPT
			? JSVAL_CRYPTO_KEY_USAGE_ENCRYPT
			: JSVAL_CRYPTO_KEY_USAGE_DECRYPT;
		size_t output_len = 0;

		error.name = NULL;
		error.message = NULL;
		if (jsval_subtle_crypto_aes_ctr_key_validate(region,
				jsval_crypto_key_value(task->key_off), required, 0, &key,
				&error) < 0) {
			return jsval_subtle_crypto_reject(region, promise_value,
					error.name, error.message);
		}
		if (jscrypto_aes_ctr_crypt(jsval_native_crypto_key_bytes(region, key),
				key->key_byte_length,
				jsval_native_microtask_subtle_aes_ctr_counter(task),
				task->counter_len, task->length_bits,
				jsval_native_microtask_subtle_aes_ctr_data(task), task->data_len,
				NULL, 0, &output_len) < 0
				|| jsval_array_buffer_new(region, output_len, &result) < 0) {
			if (jsval_dom_exception_new_utf8(region, operation_error_name,
					operation_error_message, &reason) < 0) {
				return -1;
			}
			return jsval_promise_reject(region, promise_value, reason);
		}
		if (jscrypto_aes_ctr_crypt(jsval_native_crypto_key_bytes(region, key),
				key->key_byte_length,
				jsval_native_microtask_subtle_aes_ctr_counter(task),
				task->counter_len, task->length_bits,
				jsval_native_microtask_subtle_aes_ctr_data(task), task->data_len,
				jsval_native_array_buffer_bytes(
					jsval_native_array_buffer(region, result)),
				output_len, NULL) < 0) {
			if (jsval_dom_exception_new_utf8(region, operation_error_name,
					operation_error_message, &reason) < 0) {
				return -1;
			}
			return jsval_promise_reject(region, promise_value, reason);
		}
		return jsval_promise_resolve(region, promise_value, result);
	}
	default:
		errno = EINVAL;
		return -1;
	}
}

