int
jsval_object_copy_own(jsval_region_t *region, jsval_t dst, jsval_t src)
{
	jsval_native_object_t *dst_native;
	jsval_native_prop_t *dst_props;
	jsval_object_copy_action_t *actions = NULL;
	size_t dst_len;
	size_t src_len;
	size_t append_count = 0;
	size_t i;

	if (region == NULL || dst.kind != JSVAL_KIND_OBJECT
			|| src.kind != JSVAL_KIND_OBJECT) {
		errno = EINVAL;
		return -1;
	}
	if (dst.repr != JSVAL_REPR_NATIVE) {
		errno = ENOTSUP;
		return -1;
	}
	if (src.repr != JSVAL_REPR_NATIVE && src.repr != JSVAL_REPR_JSON) {
		errno = EINVAL;
		return -1;
	}

	dst_native = jsval_native_object(region, dst);
	if (dst_native == NULL) {
		errno = EINVAL;
		return -1;
	}

	dst_len = dst_native->len;
	src_len = jsval_object_size(region, src);
	if (src_len > 0) {
		if (jsval_region_reserve(region, src_len * sizeof(*actions),
				JSVAL_ALIGN, NULL, (void **)&actions) < 0) {
			return -1;
		}
	}

	for (i = 0; i < src_len; i++) {
		jsval_t key;
		jsval_t value;
		size_t index;
		int found;

		if (jsval_object_key_at(region, src, i, &key) < 0
				|| jsval_object_value_at(region, src, i, &value) < 0) {
			return -1;
		}
		if (!jsval_key_is_property_name(key)) {
			errno = EINVAL;
			return -1;
		}

		found = jsval_native_object_find_key(region, dst_native, key, &index);
		if (found < 0) {
			return -1;
		}
		if (!found) {
			found = jsval_object_copy_find_planned_key(region, actions, i, key,
					&index);
			if (found < 0) {
				return -1;
			}
		}
		if (!found) {
			index = dst_len + append_count++;
			actions[i].append = 1;
		} else {
			actions[i].append = 0;
		}
		actions[i].key = key;
		actions[i].value = value;
		actions[i].index = index;
		actions[i].name = jsval_undefined();
	}

	if (dst_len + append_count > dst_native->cap) {
		errno = ENOBUFS;
		return -1;
	}

	for (i = 0; i < src_len; i++) {
		if (!actions[i].append) {
			continue;
		}
		if (jsval_object_key_to_native(region, actions[i].key,
				&actions[i].name) < 0) {
			return -1;
		}
	}

	dst_props = jsval_native_object_props(dst_native);
	for (i = 0; i < src_len; i++) {
		if (actions[i].append) {
			dst_props[actions[i].index].name = actions[i].name;
		}
		dst_props[actions[i].index].value = actions[i].value;
	}
	dst_native->len = dst_len + append_count;
	return 0;
}

int
jsval_object_clone_own(jsval_region_t *region, jsval_t src, size_t capacity,
		jsval_t *value_ptr)
{
	jsval_t clone;
	size_t src_len;

	if (region == NULL || value_ptr == NULL || src.kind != JSVAL_KIND_OBJECT) {
		errno = EINVAL;
		return -1;
	}
	if (src.repr != JSVAL_REPR_NATIVE && src.repr != JSVAL_REPR_JSON) {
		errno = EINVAL;
		return -1;
	}

	src_len = jsval_object_size(region, src);
	if (capacity < src_len) {
		errno = ENOBUFS;
		return -1;
	}

	if (jsval_object_new(region, capacity, &clone) < 0) {
		return -1;
	}
	if (jsval_object_copy_own(region, clone, src) < 0) {
		return -1;
	}

	*value_ptr = clone;
	return 0;
}

int jsval_object_set_key(jsval_region_t *region, jsval_t object, jsval_t key,
		jsval_t value)
{
	size_t index;
	jsval_native_object_t *native;
	jsval_native_prop_t *props;
	jsval_t name;
	int found;

	if (region == NULL || !jsval_key_is_property_name(key)) {
		errno = EINVAL;
		return -1;
	}
	if (object.kind != JSVAL_KIND_OBJECT || object.repr != JSVAL_REPR_NATIVE) {
		errno = ENOTSUP;
		return -1;
	}

	native = jsval_native_object(region, object);
	if (native == NULL) {
		errno = EINVAL;
		return -1;
	}

	props = jsval_native_object_props(native);
	found = jsval_native_object_find_key(region, native, key, &index);
	if (found < 0) {
		return -1;
	}
	if (found) {
		props[index].value = value;
		return 0;
	}

	if (native->len >= native->cap) {
		errno = ENOBUFS;
		return -1;
	}
	if (jsval_object_key_to_native(region, key, &name) < 0) {
		return -1;
	}
	props[native->len].name = name;
	props[native->len].value = value;
	native->len++;
	return 0;
}

int jsval_object_set_utf8(jsval_region_t *region, jsval_t object, const uint8_t *key, size_t key_len, jsval_t value)
{
	size_t index;
	jsval_native_object_t *native;
	jsval_native_prop_t *props;
	int found;

	if (object.kind != JSVAL_KIND_OBJECT || object.repr != JSVAL_REPR_NATIVE) {
		errno = ENOTSUP;
		return -1;
	}

	native = jsval_native_object(region, object);
	if (native == NULL) {
		errno = EINVAL;
		return -1;
	}

	props = jsval_native_object_props(native);
	found = jsval_native_object_find_utf8(region, native, key, key_len, &index);
	if (found < 0) {
		return -1;
	}
	if (found) {
		props[index].value = value;
		return 0;
	}

	if (native->len >= native->cap) {
		errno = ENOBUFS;
		return -1;
	}

	{
		jsval_t name;
		if (jsval_string_new_utf8(region, key, key_len, &name) < 0) {
			return -1;
		}
		props[native->len].name = name;
		props[native->len].value = value;
		native->len++;
	}

	return 0;
}

int jsval_object_delete_key(jsval_region_t *region, jsval_t object,
		jsval_t key, int *deleted_ptr)
{
	jsval_native_object_t *native;
	jsval_native_prop_t *props;
	size_t index;
	size_t i;
	int found;

	if (region == NULL || deleted_ptr == NULL || !jsval_key_is_property_name(key)) {
		errno = EINVAL;
		return -1;
	}
	if (object.kind != JSVAL_KIND_OBJECT) {
		errno = EINVAL;
		return -1;
	}
	if (object.repr == JSVAL_REPR_JSON) {
		if (key.kind == JSVAL_KIND_SYMBOL) {
			*deleted_ptr = 0;
			return 0;
		}
		errno = ENOTSUP;
		return -1;
	}
	if (object.repr != JSVAL_REPR_NATIVE) {
		errno = ENOTSUP;
		return -1;
	}

	native = jsval_native_object(region, object);
	if (native == NULL) {
		errno = EINVAL;
		return -1;
	}

	found = jsval_native_object_find_key(region, native, key, &index);
	if (found < 0) {
		return -1;
	}
	if (!found) {
		*deleted_ptr = 0;
		return 0;
	}

	props = jsval_native_object_props(native);
	for (i = index + 1; i < native->len; i++) {
		props[i - 1] = props[i];
	}
	props[native->len - 1].name = jsval_undefined();
	props[native->len - 1].value = jsval_undefined();
	native->len--;
	*deleted_ptr = 1;
	return 0;
}

