int jsval_request_prewarm_body(jsval_region_t *region, jsval_t request,
		jsmethod_error_t *error)
{
	jsval_native_request_t *native;
	jsval_off_t source_off;
	size_t budget;
	jsval_t drain_promise;
	jsval_promise_state_t state;
	jsval_t drained_value;
	size_t drained_len = 0;
	jsval_t buffer;
	jsval_native_array_buffer_t *dst_buf;
	jsval_native_body_source_t *src;

	if (region == NULL) {
		errno = EINVAL;
		return -1;
	}
	native = jsval_native_request(region, request);
	if (native == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (!native->body_is_streaming) {
		return 0;
	}
	if (native->body_used) {
		errno = EACCES;
		return -1;
	}

	source_off = native->body_source_off;
	src = jsval_native_body_source(region, source_off);
	if (src == NULL) {
		errno = EINVAL;
		return -1;
	}
	budget = JSVAL_FETCH_BODY_DEFAULT_LIMIT;
	if (src->content_length_hint != SIZE_MAX
			&& src->content_length_hint < budget) {
		budget = src->content_length_hint;
	}

	if (jsval_body_consume_streaming(region, source_off, budget,
			JSVAL_BODY_CONSUME_ARRAY_BUFFER, &drain_promise) < 0) {
		return -1;
	}
	/* Pump the drain locally. */
	while (1) {
		if (jsval_promise_state(region, drain_promise, &state) < 0) {
			return -1;
		}
		if (state != JSVAL_PROMISE_STATE_PENDING) {
			break;
		}
		if (jsval_microtask_pending(region) == 0) {
			errno = EDEADLK;
			return -1;
		}
		if (jsval_microtask_drain(region, error) < 0) {
			return -1;
		}
	}
	if (state == JSVAL_PROMISE_STATE_REJECTED) {
		errno = EIO;
		return -1;
	}
	if (jsval_promise_result(region, drain_promise, &drained_value) < 0) {
		return -1;
	}
	if (drained_value.kind != JSVAL_KIND_ARRAY_BUFFER) {
		errno = EINVAL;
		return -1;
	}
	if (jsval_array_buffer_byte_length(region, drained_value,
			&drained_len) < 0) {
		return -1;
	}

	/* Copy drained bytes into a fresh body_buffer so the Request owns
	 * a stable eager body. Keeping the drain's ArrayBuffer directly
	 * would also work, but the fresh copy keeps the Request's shape
	 * identical to an eagerly-constructed one. */
	if (jsval_array_buffer_new(region, drained_len, &buffer) < 0) {
		return -1;
	}
	if (drained_len > 0) {
		dst_buf = jsval_native_array_buffer(region, buffer);
		if (dst_buf == NULL) {
			errno = EINVAL;
			return -1;
		}
		if (jsval_array_buffer_copy_bytes(region, drained_value,
				jsval_native_array_buffer_bytes(dst_buf), drained_len,
				NULL) < 0) {
			return -1;
		}
	}

	/* Re-fetch the native pointer — the region may have grown. */
	native = jsval_native_request(region, request);
	if (native == NULL) {
		errno = EINVAL;
		return -1;
	}
	native->body_buffer = buffer;
	native->body_source_off = 0;
	native->body_is_streaming = 0;
	native->has_body = 1;
	native->body_used = 0;
	return 0;
}

int jsval_fetch(jsval_region_t *region, jsval_t input_value, jsval_t init_value,
		int have_init, jsval_t *promise_ptr)
{
	jsval_t request;
	jsval_t promise;
	jsval_t reason;
	const jsval_fetch_transport_t *transport;
	void *transport_userdata;
	void *state = NULL;
	jsval_native_microtask_fetch_request_t *task;
	jsval_off_t task_off;

	if (promise_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (jsval_request_new(region, input_value, init_value, have_init,
			&request) < 0) {
		return -1;
	}

	transport = region->fetch_transport;
	transport_userdata = region->fetch_transport_userdata;
	if (transport == NULL || transport->begin == NULL
			|| transport->poll == NULL) {
		if (region->fetch_waitlist_enabled) {
			/* Waitlist mode: park the (request, promise) pair in
			 * the region's FIFO and let the embedder's outbound
			 * driver pop it from its own coroutine body. */
			jsval_native_fetch_waitlist_entry_t *entry;
			jsval_off_t entry_off;

			if (jsval_promise_new(region, &promise) < 0) {
				return -1;
			}
			if (jsval_region_reserve(region, sizeof(*entry), JSVAL_ALIGN,
					&entry_off, (void **)&entry) < 0) {
				return -1;
			}
			memset(entry, 0, sizeof(*entry));
			entry->request_off = request.off;
			entry->promise_off = promise.off;
			entry->next_off = 0;
			if (region->fetch_waitlist_tail == 0) {
				region->fetch_waitlist_head = entry_off;
				region->fetch_waitlist_tail = entry_off;
			} else {
				jsval_native_fetch_waitlist_entry_t *tail =
					(jsval_native_fetch_waitlist_entry_t *)
					jsval_region_ptr(region,
							region->fetch_waitlist_tail);
				if (tail == NULL) {
					errno = EINVAL;
					return -1;
				}
				tail->next_off = entry_off;
				region->fetch_waitlist_tail = entry_off;
			}
			region->fetch_waitlist_count++;
			*promise_ptr = promise;
			return 0;
		}

		/* Preserve the reject-stub contract for embedders with no
		 * transport registered and waitlist mode disabled. */
		if (jsval_promise_new(region, &promise) < 0) {
			return -1;
		}
		if (jsval_dom_exception_new_utf8(region, "TypeError",
				"network not implemented yet", &reason) < 0) {
			return -1;
		}
		if (jsval_promise_reject(region, promise, reason) < 0) {
			return -1;
		}
		*promise_ptr = promise;
		return 0;
	}

	if (jsval_promise_new(region, &promise) < 0) {
		return -1;
	}
	if (transport->begin(transport_userdata, region, request, &state) < 0) {
		/* Translate transport begin failure into a TypeError rejection
		 * so the handler's await sees a rejected Promise instead of a
		 * fatal return. */
		if (jsval_dom_exception_new_utf8(region, "TypeError",
				"fetch transport begin failed", &reason) < 0) {
			return -1;
		}
		if (jsval_promise_reject(region, promise, reason) < 0) {
			return -1;
		}
		*promise_ptr = promise;
		return 0;
	}
	if (jsval_region_reserve(region, sizeof(*task), JSVAL_ALIGN, &task_off,
			(void **)&task) < 0) {
		if (transport->cancel != NULL) {
			transport->cancel(transport_userdata, state);
		}
		return -1;
	}
	memset(task, 0, sizeof(*task));
	task->base.kind = JSVAL_MICROTASK_KIND_FETCH_REQUEST;
	task->promise_off = promise.off;
	task->transport_state = state;
	task->transport_vtable = transport;
	task->transport_userdata = transport_userdata;
	if (jsval_microtask_push(region, task_off, &task->base) < 0) {
		if (transport->cancel != NULL) {
			transport->cancel(transport_userdata, state);
		}
		return -1;
	}
	*promise_ptr = promise;
	return 0;
}

/* =========================================================================
 * Lazy body sources + FETCH_BODY_DRAIN microtask
 * ========================================================================= */

#define JSVAL_FETCH_BODY_DRAIN_BATCH 4096

int jsval_fetch_emit_header_into(void *userdata,
		const uint8_t *name, size_t name_len,
		const uint8_t *value, size_t value_len)
{
	jsval_fetch_header_emit_ctx_t *ctx;
	jsval_t name_val;
	jsval_t value_val;

	if (userdata == NULL || name == NULL
			|| (value == NULL && value_len > 0)) {
		errno = EINVAL;
		return -1;
	}
	ctx = (jsval_fetch_header_emit_ctx_t *)userdata;
	if (ctx->region == NULL || ctx->headers.kind != JSVAL_KIND_HEADERS
			|| ctx->headers.repr != JSVAL_REPR_NATIVE) {
		errno = EINVAL;
		return -1;
	}
	if (jsval_string_new_utf8(ctx->region, name, name_len, &name_val) < 0) {
		return -1;
	}
	if (jsval_string_new_utf8(ctx->region, value, value_len, &value_val) < 0) {
		return -1;
	}
	return jsval_headers_append(ctx->region, ctx->headers, name_val,
			value_val);
}

static jsval_native_body_source_t *
jsval_native_body_source(jsval_region_t *region, jsval_off_t off)
{
	if (off == 0) {
		return NULL;
	}
	return (jsval_native_body_source_t *)jsval_region_ptr(region, off);
}

static int jsval_body_source_new(jsval_region_t *region,
		const jsval_body_source_vtable_t *vtable, void *userdata,
		size_t content_length_hint, jsval_off_t *off_ptr)
{
	jsval_native_body_source_t *src;
	jsval_off_t off;

	if (region == NULL || vtable == NULL || off_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (jsval_region_reserve(region, sizeof(*src), JSVAL_ALIGN, &off,
			(void **)&src) < 0) {
		return -1;
	}
	src->vtable = vtable;
	src->userdata = userdata;
	src->content_length_hint = content_length_hint;
	src->closed = 0;
	memset(src->reserved, 0, sizeof(src->reserved));
	src->parked_stream_off = 0;
	src->parked_drain_off = 0;
	*off_ptr = off;
	return 0;
}

static void jsval_body_source_close_once(jsval_native_body_source_t *src)
{
	if (src == NULL || src->closed) {
		return;
	}
	src->closed = 1;
	if (src->vtable != NULL && src->vtable->close != NULL) {
		src->vtable->close(src->userdata);
	}
}

int jsval_request_new_from_parts(jsval_region_t *region,
		jsval_t method_value,
		jsval_t url_value,
		jsval_t headers_value,
		const jsval_body_source_vtable_t *body_vtable,
		void *body_userdata,
		size_t content_length_hint,
		jsval_t *value_ptr)
{
	jsval_native_request_t *native;
	jsval_off_t off;
	uint8_t method = JSVAL_HTTP_METHOD_GET;
	jsval_off_t source_off = 0;
	size_t budget = JSVAL_FETCH_BODY_DEFAULT_LIMIT;

	if (region == NULL || value_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (headers_value.kind != JSVAL_KIND_HEADERS
			|| url_value.kind != JSVAL_KIND_STRING) {
		errno = EINVAL;
		return -1;
	}
	if (method_value.kind == JSVAL_KIND_STRING) {
		if (jsval_http_method_from_string(region, method_value, &method) < 0) {
			return -1;
		}
	}
	if (jsval_http_method_is_forbidden(method)) {
		errno = EACCES;
		return -1;
	}
	if (body_vtable != NULL) {
		if (content_length_hint != SIZE_MAX
				&& content_length_hint < budget) {
			budget = content_length_hint;
		}
		if (jsval_body_source_new(region, body_vtable, body_userdata,
				content_length_hint, &source_off) < 0) {
			return -1;
		}
	}

	if (jsval_region_reserve(region, sizeof(*native), JSVAL_ALIGN, &off,
			(void **)&native) < 0) {
		return -1;
	}
	memset(native, 0, sizeof(*native));
	native->url = url_value;
	native->headers = headers_value;
	native->body_buffer = jsval_undefined();
	native->body_source_off = source_off;
	native->method = method;
	native->has_body = source_off != 0 ? 1 : 0;
	native->body_is_streaming = source_off != 0 ? 1 : 0;
	(void)budget;
	*value_ptr = jsval_undefined();
	value_ptr->kind = JSVAL_KIND_REQUEST;
	value_ptr->repr = JSVAL_REPR_NATIVE;
	value_ptr->off = off;
	return 0;
}

int jsval_response_new_from_parts(jsval_region_t *region,
		uint16_t status,
		jsval_t status_text_value,
		jsval_t headers_value,
		const jsval_body_source_vtable_t *body_vtable,
		void *body_userdata,
		size_t content_length_hint,
		jsval_t *value_ptr)
{
	jsval_native_response_t *native;
	jsval_off_t off;
	jsval_off_t source_off = 0;
	jsval_t status_text = status_text_value;

	if (region == NULL || value_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (headers_value.kind != JSVAL_KIND_HEADERS) {
		errno = EINVAL;
		return -1;
	}
	if (status_text.kind != JSVAL_KIND_STRING) {
		if (jsval_string_new_utf8(region, (const uint8_t *)"", 0,
				&status_text) < 0) {
			return -1;
		}
	}
	if (body_vtable != NULL) {
		if (jsval_body_source_new(region, body_vtable, body_userdata,
				content_length_hint, &source_off) < 0) {
			return -1;
		}
	}

	if (jsval_region_reserve(region, sizeof(*native), JSVAL_ALIGN, &off,
			(void **)&native) < 0) {
		return -1;
	}
	memset(native, 0, sizeof(*native));
	native->url = jsval_undefined();
	native->headers = headers_value;
	native->status_text = status_text;
	native->body_buffer = jsval_undefined();
	native->body_source_off = source_off;
	native->status = status;
	native->type = JSVAL_RESPONSE_TYPE_DEFAULT;
	native->has_body = source_off != 0 ? 1 : 0;
	native->body_is_streaming = source_off != 0 ? 1 : 0;
	*value_ptr = jsval_undefined();
	value_ptr->kind = JSVAL_KIND_RESPONSE;
	value_ptr->repr = JSVAL_REPR_NATIVE;
	value_ptr->off = off;
	return 0;
}

/* Schedule a body drain microtask against `source_off`. Returns a pending
 * promise in `*promise_out`. Stores `consume_mode` on the task. */
static int jsval_body_drain_schedule(jsval_region_t *region,
		jsval_off_t source_off, size_t budget, uint8_t consume_mode,
		jsval_t *promise_out)
{
	jsval_native_microtask_fetch_body_drain_t *task;
	jsval_off_t task_off;
	jsval_t promise;
	jsval_t initial_buffer;
	size_t initial_cap;

	if (jsval_promise_new(region, &promise) < 0) {
		return -1;
	}
	initial_cap = budget == 0 || budget == SIZE_MAX
			? JSVAL_FETCH_BODY_DRAIN_BATCH
			: (budget < JSVAL_FETCH_BODY_DRAIN_BATCH
					? budget : JSVAL_FETCH_BODY_DRAIN_BATCH);
	if (jsval_array_buffer_new(region, initial_cap, &initial_buffer) < 0) {
		return -1;
	}
	if (jsval_region_reserve(region, sizeof(*task), JSVAL_ALIGN, &task_off,
			(void **)&task) < 0) {
		return -1;
	}
	memset(task, 0, sizeof(*task));
	task->base.kind = JSVAL_MICROTASK_KIND_FETCH_BODY_DRAIN;
	task->promise_off = promise.off;
	task->buffer_off = initial_buffer.off;
	task->source_off = source_off;
	task->written_len = 0;
	task->budget = budget;
	task->consume_mode = consume_mode;
	if (jsval_microtask_push(region, task_off, &task->base) < 0) {
		return -1;
	}
	*promise_out = promise;
	return 0;
}

static int jsval_body_drain_reject(jsval_region_t *region,
		jsval_native_microtask_fetch_body_drain_t *task,
		const char *message)
{
	jsval_t promise_value;
	jsval_t reason;
	jsval_native_body_source_t *src;

	promise_value = jsval_promise_value(task->promise_off);
	src = jsval_native_body_source(region, task->source_off);
	jsval_body_source_close_once(src);
	if (jsval_dom_exception_new_utf8(region, "TypeError", message,
			&reason) < 0) {
		return -1;
	}
	return jsval_promise_reject(region, promise_value, reason);
}

static int jsval_body_drain_resolve_eof(jsval_region_t *region,
		jsval_native_microtask_fetch_body_drain_t *task)
{
	jsval_t promise_value;
	jsval_t buffer_value;
	jsval_t resolved = jsval_undefined();
	jsval_native_array_buffer_t *buffer;
	jsval_native_body_source_t *src;
	size_t len = task->written_len;
	uint8_t *bytes;

	promise_value = jsval_promise_value(task->promise_off);
	src = jsval_native_body_source(region, task->source_off);
	jsval_body_source_close_once(src);

	buffer_value = jsval_undefined();
	buffer_value.kind = JSVAL_KIND_ARRAY_BUFFER;
	buffer_value.repr = JSVAL_REPR_NATIVE;
	buffer_value.off = task->buffer_off;
	buffer = jsval_native_array_buffer(region, buffer_value);
	if (buffer == NULL) {
		errno = EINVAL;
		return -1;
	}
	bytes = jsval_native_array_buffer_bytes(buffer);

	switch ((jsval_body_consume_mode_t)task->consume_mode) {
	case JSVAL_BODY_CONSUME_TEXT:
		if (jsval_string_new_utf8(region, bytes, len, &resolved) < 0) {
			return -1;
		}
		break;
	case JSVAL_BODY_CONSUME_JSON:
	{
		if (len == 0) {
			jsval_t reason;
			if (jsval_dom_exception_new_utf8(region, "SyntaxError",
					"empty body", &reason) < 0) {
				return -1;
			}
			return jsval_promise_reject(region, promise_value, reason);
		}
		if (jsval_json_parse(region, bytes, len, 256, &resolved) < 0) {
			jsval_t reason;
			if (jsval_dom_exception_new_utf8(region, "SyntaxError",
					"invalid JSON", &reason) < 0) {
				return -1;
			}
			return jsval_promise_reject(region, promise_value, reason);
		}
		break;
	}
	case JSVAL_BODY_CONSUME_ARRAY_BUFFER:
	{
		/* Materialize a fresh ArrayBuffer of exactly `len` bytes. */
		jsval_t out;
		if (jsval_array_buffer_new(region, len, &out) < 0) {
			return -1;
		}
		if (len > 0) {
			jsval_native_array_buffer_t *dst =
					jsval_native_array_buffer(region, out);
			if (dst == NULL) {
				errno = EINVAL;
				return -1;
			}
			/* Re-fetch the drain's buffer (region may have grown). */
			buffer = jsval_native_array_buffer(region, buffer_value);
			if (buffer == NULL) {
				errno = EINVAL;
				return -1;
			}
			memcpy(jsval_native_array_buffer_bytes(dst),
					jsval_native_array_buffer_bytes(buffer), len);
		}
		resolved = out;
		break;
	}
	case JSVAL_BODY_CONSUME_BYTES:
	{
		jsval_t typed;
		if (jsval_typed_array_new(region, JSVAL_TYPED_ARRAY_UINT8, len,
				&typed) < 0) {
			return -1;
		}
		if (len > 0) {
			jsval_t backing;
			jsval_native_array_buffer_t *dst;
			if (jsval_typed_array_buffer(region, typed, &backing) < 0) {
				return -1;
			}
			dst = jsval_native_array_buffer(region, backing);
			if (dst == NULL) {
				errno = EINVAL;
				return -1;
			}
			buffer = jsval_native_array_buffer(region, buffer_value);
			if (buffer == NULL) {
				errno = EINVAL;
				return -1;
			}
			memcpy(jsval_native_array_buffer_bytes(dst),
					jsval_native_array_buffer_bytes(buffer), len);
		}
		resolved = typed;
		break;
	}
	default:
		errno = EINVAL;
		return -1;
	}

	return jsval_promise_resolve(region, promise_value, resolved);
}

/* Grow the drain's accumulating ArrayBuffer so that total capacity covers
 * at least `need` bytes. Updates task->buffer_off on success. */
static int jsval_body_drain_grow(jsval_region_t *region,
		jsval_native_microtask_fetch_body_drain_t *task, size_t need)
{
	jsval_t old_value;
	jsval_t new_value;
	jsval_native_array_buffer_t *old_buf;
	jsval_native_array_buffer_t *new_buf;
	size_t old_cap = 0;
	size_t new_cap;

	old_value = jsval_undefined();
	old_value.kind = JSVAL_KIND_ARRAY_BUFFER;
	old_value.repr = JSVAL_REPR_NATIVE;
	old_value.off = task->buffer_off;
	if (jsval_array_buffer_byte_length(region, old_value, &old_cap) < 0) {
		return -1;
	}
	if (need <= old_cap) {
		return 0;
	}
	new_cap = old_cap == 0 ? JSVAL_FETCH_BODY_DRAIN_BATCH : old_cap;
	while (new_cap < need) {
		if (new_cap > SIZE_MAX / 2) {
			errno = EOVERFLOW;
			return -1;
		}
		new_cap *= 2;
	}
	if (jsval_array_buffer_new(region, new_cap, &new_value) < 0) {
		return -1;
	}
	new_buf = jsval_native_array_buffer(region, new_value);
	if (new_buf == NULL) {
		errno = EINVAL;
		return -1;
	}
	old_buf = jsval_native_array_buffer(region, old_value);
	if (old_buf == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (task->written_len > 0) {
		memcpy(jsval_native_array_buffer_bytes(new_buf),
				jsval_native_array_buffer_bytes(old_buf), task->written_len);
	}
	task->buffer_off = new_value.off;
	return 0;
}

static int jsval_fetch_run_body_drain(jsval_region_t *region,
		jsval_native_microtask_fetch_body_drain_t *task, jsval_off_t task_off)
{
	uint8_t scratch[JSVAL_FETCH_BODY_DRAIN_BATCH];
	size_t n = 0;
	jsval_body_source_status_t status = JSVAL_BODY_SOURCE_STATUS_ERROR;
	jsval_native_body_source_t *src;
	int rc;

	if (region == NULL || task == NULL) {
		errno = EINVAL;
		return -1;
	}
	src = jsval_native_body_source(region, task->source_off);
	if (src == NULL || src->vtable == NULL || src->vtable->read == NULL) {
		return jsval_body_drain_reject(region, task, "invalid body source");
	}
	rc = src->vtable->read(src->userdata, scratch, sizeof(scratch), &n,
			&status);
	if (rc < 0 || status == JSVAL_BODY_SOURCE_STATUS_ERROR) {
		return jsval_body_drain_reject(region, task,
				"network error reading body");
	}
	if (status == JSVAL_BODY_SOURCE_STATUS_PENDING) {
		/* Park on source. The producer side calls
		 * jsval_body_source_notify after each push / mark_eof /
		 * mark_error; that wake will re-enqueue this task. The
		 * task struct stays valid because it's region-allocated
		 * and the region isn't reset between park and wake. */
		src->parked_drain_off = task_off;
		return 0;
	}
	if (n > 0) {
		size_t new_total;
		jsval_native_array_buffer_t *buf;
		jsval_t buffer_value;

		if (n > SIZE_MAX - task->written_len) {
			return jsval_body_drain_reject(region, task,
					"body exceeds length limit");
		}
		new_total = task->written_len + n;
		if (new_total > task->budget) {
			return jsval_body_drain_reject(region, task,
					"body exceeds length limit");
		}
		if (jsval_body_drain_grow(region, task, new_total) < 0) {
			if (errno == ENOBUFS) {
				return jsval_body_drain_reject(region, task,
						"body exceeds length limit");
			}
			return -1;
		}
		buffer_value = jsval_undefined();
		buffer_value.kind = JSVAL_KIND_ARRAY_BUFFER;
		buffer_value.repr = JSVAL_REPR_NATIVE;
		buffer_value.off = task->buffer_off;
		buf = jsval_native_array_buffer(region, buffer_value);
		if (buf == NULL) {
			errno = EINVAL;
			return -1;
		}
		memcpy(jsval_native_array_buffer_bytes(buf) + task->written_len,
				scratch, n);
		task->written_len = new_total;
	}
	if (status == JSVAL_BODY_SOURCE_STATUS_EOF) {
		return jsval_body_drain_resolve_eof(region, task);
	}
	/* READY with more bytes expected — re-enqueue for another pump. */
	return jsval_microtask_push(region, task_off, &task->base);
}

/* Streaming-path body consumption: schedule a drain microtask and hand back
 * its pending promise. Shared between Request and Response. */
static int jsval_body_consume_streaming(jsval_region_t *region,
		jsval_off_t source_off, size_t budget, uint8_t consume_mode,
		jsval_t *promise_out)
{
	if (source_off == 0 || promise_out == NULL) {
		errno = EINVAL;
		return -1;
	}
	return jsval_body_drain_schedule(region, source_off, budget, consume_mode,
			promise_out);
}

/*
 * Outbound-fetch microtask pump. Called by the drain for each
 * JSVAL_MICROTASK_KIND_FETCH_REQUEST task.
 *
 * PENDING: re-enqueue the task at the tail of the microtask queue so the
 *          next drain pass re-polls. Matches the pattern
 *          jsval_fetch_run_body_drain uses at the FETCH_BODY_DRAIN PENDING
 *          branch. Real scheduler integration (yield the embedder
 *          coroutine until a socket is ready) lands alongside the mnvkd
 *          adapter; this slice assumes the transport does not return
 *          PENDING indefinitely in a single drain.
 * READY  : resolve the Promise with the transport-built Response.
 * ERROR  : reject the Promise with the transport-built reason.
 */
static int jsval_fetch_run_request(jsval_region_t *region,
		jsval_native_microtask_fetch_request_t *task, jsval_off_t task_off)
{
	jsval_fetch_transport_status_t status = JSVAL_FETCH_TRANSPORT_STATUS_ERROR;
	jsval_t promise_value;
	jsval_t response_value = jsval_undefined();
	jsval_t reason_value = jsval_undefined();
	int rc;

	if (region == NULL || task == NULL || task->transport_vtable == NULL
			|| task->transport_vtable->poll == NULL) {
		errno = EINVAL;
		return -1;
	}
	promise_value = jsval_promise_value(task->promise_off);
	rc = task->transport_vtable->poll(task->transport_userdata, region,
			task->transport_state, &status, &response_value, &reason_value);
	if (rc < 0) {
		jsval_t fallback;
		if (jsval_dom_exception_new_utf8(region, "TypeError",
				"fetch transport poll failed", &fallback) < 0) {
			return -1;
		}
		return jsval_promise_reject(region, promise_value, fallback);
	}
	if (status == JSVAL_FETCH_TRANSPORT_STATUS_PENDING) {
		return jsval_microtask_push(region, task_off, &task->base);
	}
	if (status == JSVAL_FETCH_TRANSPORT_STATUS_ERROR) {
		return jsval_promise_reject(region, promise_value, reason_value);
	}
	if (status != JSVAL_FETCH_TRANSPORT_STATUS_READY) {
		errno = EINVAL;
		return -1;
	}
	if (response_value.kind != JSVAL_KIND_RESPONSE) {
		jsval_t fallback;
		if (jsval_dom_exception_new_utf8(region, "TypeError",
				"fetch transport returned non-Response", &fallback) < 0) {
			return -1;
		}
		return jsval_promise_reject(region, promise_value, fallback);
	}
	return jsval_promise_resolve(region, promise_value, response_value);
}

/* -------------------- ReadableStream --------------------- */

static jsval_native_readable_stream_t *jsval_native_readable_stream(
		jsval_region_t *region, jsval_t value)
{
	if (value.repr != JSVAL_REPR_NATIVE
			|| value.kind != JSVAL_KIND_READABLE_STREAM) {
		return NULL;
	}
	return (jsval_native_readable_stream_t *)jsval_region_ptr(region, value.off);
}

static jsval_native_readable_stream_t *jsval_native_readable_stream_off(
		jsval_region_t *region, jsval_off_t off)
{
	if (off == 0) {
		return NULL;
	}
	return (jsval_native_readable_stream_t *)jsval_region_ptr(region, off);
}

static jsval_native_readable_stream_reader_t *jsval_native_readable_stream_reader(
		jsval_region_t *region, jsval_t value)
{
	if (value.repr != JSVAL_REPR_NATIVE
			|| value.kind != JSVAL_KIND_READABLE_STREAM_READER) {
		return NULL;
	}
	return (jsval_native_readable_stream_reader_t *)jsval_region_ptr(region,
			value.off);
}

static int jsval_readable_stream_bytes_source_read(void *userdata,
		uint8_t *buf, size_t cap, size_t *out_len,
		jsval_body_source_status_t *status_ptr)
{
	jsval_native_readable_stream_bytes_source_t *state;
	const uint8_t *bytes;
	size_t remaining;
	size_t n;

	if (userdata == NULL || out_len == NULL || status_ptr == NULL
			|| (cap > 0 && buf == NULL)) {
		errno = EINVAL;
		return -1;
	}
	state = (jsval_native_readable_stream_bytes_source_t *)userdata;
	bytes = (const uint8_t *)(state + 1);
	remaining = state->len - state->cursor;
	if (remaining == 0) {
		*out_len = 0;
		*status_ptr = JSVAL_BODY_SOURCE_STATUS_EOF;
		return 0;
	}
	n = cap < remaining ? cap : remaining;
	memcpy(buf, bytes + state->cursor, n);
	state->cursor += n;
	*out_len = n;
	*status_ptr = JSVAL_BODY_SOURCE_STATUS_READY;
	return 0;
}

static void jsval_readable_stream_bytes_source_close(void *userdata)
{
	(void)userdata;
}

static const jsval_body_source_vtable_t
		jsval_readable_stream_bytes_source_vtable = {
	jsval_readable_stream_bytes_source_read,
	jsval_readable_stream_bytes_source_close
};

/*
 * Build a { value: Uint8Array | undefined, done: bool } object on the region.
 * When done == 1, value is undefined; when done == 0, value is a Uint8Array
 * populated with len bytes from `bytes`.
 */
static int jsval_readable_stream_make_read_result(jsval_region_t *region,
		const uint8_t *bytes, size_t len, int done, jsval_t *out)
{
	jsval_t result;
	jsval_t value = jsval_undefined();

	if (!done) {
		jsval_t backing;
		uint8_t *dst = NULL;
		size_t cap = 0;

		if (jsval_typed_array_new(region, JSVAL_TYPED_ARRAY_UINT8, len,
				&value) < 0) {
			return -1;
		}
		if (jsval_typed_array_buffer(region, value, &backing) < 0) {
			return -1;
		}
		if (jsval_array_buffer_bytes_mut(region, backing, &dst, &cap) < 0) {
			return -1;
		}
		if (len > 0 && bytes != NULL) {
			memcpy(dst, bytes, len);
		}
	}

	if (jsval_object_new(region, 2, &result) < 0) {
		return -1;
	}
	if (jsval_object_set_utf8(region, result, (const uint8_t *)"value", 5,
			value) < 0) {
		return -1;
	}
	if (jsval_object_set_utf8(region, result, (const uint8_t *)"done", 4,
			jsval_bool(done)) < 0) {
		return -1;
	}
	*out = result;
	return 0;
}

static int jsval_readable_stream_enqueue_read(jsval_region_t *region,
		jsval_off_t stream_off, jsval_off_t promise_off)
{
	jsval_native_readable_stream_t *stream;
	jsval_native_readable_stream_pending_read_t *node;
	jsval_off_t node_off;

	if (jsval_region_reserve(region, sizeof(*node),
			_Alignof(jsval_native_readable_stream_pending_read_t),
			&node_off, (void **)&node) < 0) {
		return -1;
	}
	node->next_off = 0;
	node->promise_off = promise_off;

	stream = jsval_native_readable_stream_off(region, stream_off);
	if (stream == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (stream->pending_reads_tail == 0) {
		stream->pending_reads_head = node_off;
		stream->pending_reads_tail = node_off;
	} else {
		jsval_native_readable_stream_pending_read_t *tail;
		tail = (jsval_native_readable_stream_pending_read_t *)jsval_region_ptr(
				region, stream->pending_reads_tail);
		if (tail == NULL) {
			errno = EINVAL;
			return -1;
		}
		tail->next_off = node_off;
		stream->pending_reads_tail = node_off;
	}
	return 0;
}

static jsval_off_t jsval_readable_stream_dequeue_read(jsval_region_t *region,
		jsval_native_readable_stream_t *stream)
{
	jsval_native_readable_stream_pending_read_t *node;
	jsval_off_t node_off;
	jsval_off_t promise_off;

	if (stream == NULL || stream->pending_reads_head == 0) {
		return 0;
	}
	node_off = stream->pending_reads_head;
	node = (jsval_native_readable_stream_pending_read_t *)jsval_region_ptr(
			region, node_off);
	if (node == NULL) {
		return 0;
	}
	promise_off = node->promise_off;
	stream->pending_reads_head = node->next_off;
	if (stream->pending_reads_head == 0) {
		stream->pending_reads_tail = 0;
	}
	return promise_off;
}

static int jsval_readable_stream_schedule_pump(jsval_region_t *region,
		jsval_off_t stream_off)
{
	jsval_native_readable_stream_t *stream;
	jsval_native_microtask_readable_stream_pump_t *task;
	jsval_off_t task_off;

	stream = jsval_native_readable_stream_off(region, stream_off);
	if (stream == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (stream->pump_scheduled) {
		return 0;
	}
	if (jsval_region_reserve(region, sizeof(*task), JSVAL_ALIGN, &task_off,
			(void **)&task) < 0) {
		return -1;
	}
	memset(task, 0, sizeof(*task));
	task->base.kind = JSVAL_MICROTASK_KIND_READABLE_STREAM_PUMP;
	task->stream_off = stream_off;
	/* Re-lookup after reserve. */
	stream = jsval_native_readable_stream_off(region, stream_off);
	if (stream == NULL) {
		errno = EINVAL;
		return -1;
	}
	stream->pump_scheduled = 1;
	return jsval_microtask_push(region, task_off, &task->base);
}

/*
 * Like jsval_readable_stream_new_from_source but reuses an existing
 * source allocated elsewhere (e.g. a streaming Request/Response). The
 * caller keeps ownership of the source storage. Parking + notify on
 * the shared source wake this stream's pump.
 */
static int jsval_readable_stream_new_wrapping_source(jsval_region_t *region,
		jsval_off_t source_off, jsval_t *value_ptr)
{
	jsval_native_readable_stream_t *stream;
	void *ptr = NULL;

	if (region == NULL || source_off == 0 || value_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (jsval_region_alloc(region, sizeof(*stream),
			_Alignof(jsval_native_readable_stream_t), &ptr) < 0) {
		return -1;
	}
	stream = (jsval_native_readable_stream_t *)ptr;
	memset(stream, 0, sizeof(*stream));
	stream->source_off = source_off;
	stream->error_reason = jsval_undefined();
	stream->state = JSVAL_READABLE_STREAM_STATE_READABLE;

	*value_ptr = jsval_native_make_value(region, stream,
			JSVAL_KIND_READABLE_STREAM);
	return 0;
}

int jsval_readable_stream_new_from_source(jsval_region_t *region,
		const jsval_body_source_vtable_t *vtable, void *userdata,
		jsval_t *value_ptr)
{
	jsval_native_readable_stream_t *stream;
	jsval_native_body_source_t *source;
	jsval_off_t source_off;
	void *ptr = NULL;

	if (region == NULL || vtable == NULL || value_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (jsval_region_reserve(region, sizeof(*source),
			_Alignof(jsval_native_body_source_t), &source_off,
			(void **)&source) < 0) {
		return -1;
	}
	source->vtable = vtable;
	source->userdata = userdata;
	source->content_length_hint = SIZE_MAX;
	source->closed = 0;
	memset(source->reserved, 0, sizeof(source->reserved));
	source->parked_stream_off = 0;
	source->parked_drain_off = 0;

	if (jsval_region_alloc(region, sizeof(*stream),
			_Alignof(jsval_native_readable_stream_t), &ptr) < 0) {
		return -1;
	}
	stream = (jsval_native_readable_stream_t *)ptr;
	memset(stream, 0, sizeof(*stream));
	stream->source_off = source_off;
	stream->error_reason = jsval_undefined();
	stream->state = JSVAL_READABLE_STREAM_STATE_READABLE;

	*value_ptr = jsval_native_make_value(region, stream,
			JSVAL_KIND_READABLE_STREAM);
	return 0;
}

int jsval_readable_stream_new_from_bytes(jsval_region_t *region,
		const uint8_t *bytes, size_t len, jsval_t *value_ptr)
{
	jsval_native_readable_stream_bytes_source_t *state;
	uint8_t *state_bytes;
	jsval_off_t state_off;
	size_t total;

	if (region == NULL || value_ptr == NULL
			|| (bytes == NULL && len != 0)) {
		errno = EINVAL;
		return -1;
	}
	if (len > SIZE_MAX - sizeof(*state)) {
		errno = EOVERFLOW;
		return -1;
	}
	total = sizeof(*state) + len;
	if (jsval_region_reserve(region, total,
			_Alignof(jsval_native_readable_stream_bytes_source_t),
			&state_off, (void **)&state) < 0) {
		return -1;
	}
	state->len = len;
	state->cursor = 0;
	state_bytes = (uint8_t *)(state + 1);
	if (len > 0) {
		memcpy(state_bytes, bytes, len);
	}
	return jsval_readable_stream_new_from_source(region,
			&jsval_readable_stream_bytes_source_vtable, state, value_ptr);
}

int jsval_readable_stream_locked(jsval_region_t *region, jsval_t stream_value,
		int *locked_ptr)
{
	jsval_native_readable_stream_t *stream;

	if (locked_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	stream = jsval_native_readable_stream(region, stream_value);
	if (stream == NULL) {
		errno = EINVAL;
		return -1;
	}
	*locked_ptr = stream->reader_off != 0 ? 1 : 0;
	return 0;
}

int jsval_readable_stream_get_reader(jsval_region_t *region,
		jsval_t stream_value, jsval_t *reader_ptr)
{
	jsval_native_readable_stream_t *stream;
	jsval_native_readable_stream_reader_t *reader;
	jsval_t reader_value;
	void *ptr = NULL;

	if (reader_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	stream = jsval_native_readable_stream(region, stream_value);
	if (stream == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (stream->reader_off != 0) {
		errno = EBUSY;
		return -1;
	}
	if (jsval_region_alloc(region, sizeof(*reader),
			_Alignof(jsval_native_readable_stream_reader_t), &ptr) < 0) {
		return -1;
	}
	reader = (jsval_native_readable_stream_reader_t *)ptr;
	memset(reader, 0, sizeof(*reader));
	reader->stream_off = stream_value.off;
	reader_value = jsval_native_make_value(region, reader,
			JSVAL_KIND_READABLE_STREAM_READER);
	/* Re-lookup stream (base is stable but be explicit). */
	stream = jsval_native_readable_stream(region, stream_value);
	if (stream == NULL) {
		errno = EINVAL;
		return -1;
	}
	stream->reader_off = reader_value.off;
	*reader_ptr = reader_value;
	return 0;
}

int jsval_readable_stream_reader_release_lock(jsval_region_t *region,
		jsval_t reader_value)
{
	jsval_native_readable_stream_reader_t *reader;
	jsval_native_readable_stream_t *stream;

	reader = jsval_native_readable_stream_reader(region, reader_value);
	if (reader == NULL) {
		errno = EINVAL;
		return -1;
	}
	stream = jsval_native_readable_stream_off(region, reader->stream_off);
	if (stream == NULL) {
		/* Already released. */
		return 0;
	}
	if (stream->pending_reads_head != 0) {
		errno = EBUSY;
		return -1;
	}
	stream->reader_off = 0;
	reader->stream_off = 0;
	return 0;
}

int jsval_readable_stream_reader_read(jsval_region_t *region,
		jsval_t reader_value, jsval_t *promise_ptr)
{
	jsval_native_readable_stream_reader_t *reader;
	jsval_native_readable_stream_t *stream;
	jsval_off_t stream_off;
	jsval_t promise;
	jsval_t result;
	jsval_t reason;
	jsval_native_body_source_t *source;
	uint8_t scratch[JSVAL_FETCH_BODY_DRAIN_BATCH];
	size_t n = 0;
	jsval_body_source_status_t status = JSVAL_BODY_SOURCE_STATUS_ERROR;
	int rc;

	if (promise_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	reader = jsval_native_readable_stream_reader(region, reader_value);
	if (reader == NULL) {
		errno = EINVAL;
		return -1;
	}
	stream_off = reader->stream_off;
	stream = jsval_native_readable_stream_off(region, stream_off);
	if (stream == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (jsval_promise_new(region, &promise) < 0) {
		return -1;
	}
	stream = jsval_native_readable_stream_off(region, stream_off);
	if (stream == NULL) {
		errno = EINVAL;
		return -1;
	}

	if (stream->state == JSVAL_READABLE_STREAM_STATE_ERRORED) {
		if (jsval_promise_reject(region, promise, stream->error_reason) < 0) {
			return -1;
		}
		*promise_ptr = promise;
		return 0;
	}
	if (stream->state == JSVAL_READABLE_STREAM_STATE_CLOSED) {
		if (jsval_readable_stream_make_read_result(region, NULL, 0, 1,
				&result) < 0) {
			return -1;
		}
		if (jsval_promise_resolve(region, promise, result) < 0) {
			return -1;
		}
		*promise_ptr = promise;
		return 0;
	}

	/* FIFO ordering: if prior reads are queued or a pump is in flight,
	 * enqueue this read behind them. */
	if (stream->pending_reads_head != 0 || stream->pump_scheduled) {
		if (jsval_readable_stream_enqueue_read(region, stream_off,
				promise.off) < 0) {
			return -1;
		}
		if (jsval_readable_stream_schedule_pump(region, stream_off) < 0) {
			return -1;
		}
		*promise_ptr = promise;
		return 0;
	}

	source = jsval_native_body_source(region, stream->source_off);
	if (source == NULL || source->vtable == NULL
			|| source->vtable->read == NULL) {
		if (jsval_dom_exception_new_utf8(region, "TypeError",
				"invalid stream source", &reason) < 0) {
			return -1;
		}
		stream = jsval_native_readable_stream_off(region, stream_off);
		if (stream == NULL) {
			errno = EINVAL;
			return -1;
		}
		stream->state = JSVAL_READABLE_STREAM_STATE_ERRORED;
		stream->error_reason = reason;
		if (jsval_promise_reject(region, promise, reason) < 0) {
			return -1;
		}
		*promise_ptr = promise;
		return 0;
	}

	rc = source->vtable->read(source->userdata, scratch, sizeof(scratch),
			&n, &status);
	if (rc < 0 || status == JSVAL_BODY_SOURCE_STATUS_ERROR) {
		if (jsval_dom_exception_new_utf8(region, "TypeError",
				"stream source error", &reason) < 0) {
			return -1;
		}
		stream = jsval_native_readable_stream_off(region, stream_off);
		if (stream == NULL) {
			errno = EINVAL;
			return -1;
		}
		stream->state = JSVAL_READABLE_STREAM_STATE_ERRORED;
		stream->error_reason = reason;
		if (jsval_promise_reject(region, promise, reason) < 0) {
			return -1;
		}
		*promise_ptr = promise;
		return 0;
	}

	if (status == JSVAL_BODY_SOURCE_STATUS_EOF) {
		stream = jsval_native_readable_stream_off(region, stream_off);
		if (stream == NULL) {
			errno = EINVAL;
			return -1;
		}
		stream->state = JSVAL_READABLE_STREAM_STATE_CLOSED;
		source = jsval_native_body_source(region, stream->source_off);
		jsval_body_source_close_once(source);
		/* EOF may carry a final chunk. Deliver bytes first; next read
		 * will see stream->state == CLOSED and return { done: true }. */
		if (n > 0) {
			if (jsval_readable_stream_make_read_result(region, scratch, n, 0,
					&result) < 0) {
				return -1;
			}
		} else {
			if (jsval_readable_stream_make_read_result(region, NULL, 0, 1,
					&result) < 0) {
				return -1;
			}
		}
		if (jsval_promise_resolve(region, promise, result) < 0) {
			return -1;
		}
		*promise_ptr = promise;
		return 0;
	}

	if (status == JSVAL_BODY_SOURCE_STATUS_PENDING || n == 0) {
		/* Queue this read and park on the source. The producer
		 * calls jsval_body_source_notify after it pushes more
		 * bytes (or flags EOF/ERROR), which schedules a fresh
		 * pump microtask. Without this parking, re-scheduling
		 * the pump here would busy-loop the microtask drain. */
		if (jsval_readable_stream_enqueue_read(region, stream_off,
				promise.off) < 0) {
			return -1;
		}
		source = jsval_native_body_source(region, stream->source_off);
		if (source == NULL) {
			errno = EINVAL;
			return -1;
		}
		source->parked_stream_off = stream_off;
		*promise_ptr = promise;
		return 0;
	}

	if (jsval_readable_stream_make_read_result(region, scratch, n, 0,
			&result) < 0) {
		return -1;
	}
	if (jsval_promise_resolve(region, promise, result) < 0) {
		return -1;
	}
	*promise_ptr = promise;
	return 0;
}

int jsval_readable_stream_cancel(jsval_region_t *region, jsval_t stream_value,
		jsval_t reason, jsval_t *promise_ptr)
{
	jsval_native_readable_stream_t *stream;
	jsval_off_t stream_off;
	jsval_t promise;
	jsval_native_body_source_t *source;
	jsval_off_t read_promise_off;
	(void)reason;

	if (promise_ptr == NULL) {
		errno = EINVAL;
		return -1;
	}
	stream = jsval_native_readable_stream(region, stream_value);
	if (stream == NULL) {
		errno = EINVAL;
		return -1;
	}
	stream_off = stream_value.off;

	if (jsval_promise_new(region, &promise) < 0) {
		return -1;
	}
	stream = jsval_native_readable_stream_off(region, stream_off);
	if (stream == NULL) {
		errno = EINVAL;
		return -1;
	}
	if (stream->state == JSVAL_READABLE_STREAM_STATE_ERRORED) {
		if (jsval_promise_reject(region, promise, stream->error_reason)
				< 0) {
			return -1;
		}
		*promise_ptr = promise;
		return 0;
	}
	stream->state = JSVAL_READABLE_STREAM_STATE_CLOSED;
	source = jsval_native_body_source(region, stream->source_off);
	jsval_body_source_close_once(source);

	while ((read_promise_off = jsval_readable_stream_dequeue_read(region,
			stream)) != 0) {
		jsval_t done_result;
		jsval_t read_promise = jsval_promise_value(read_promise_off);

		if (jsval_readable_stream_make_read_result(region, NULL, 0, 1,
				&done_result) < 0) {
			return -1;
		}
		stream = jsval_native_readable_stream_off(region, stream_off);
		if (stream == NULL) {
			errno = EINVAL;
			return -1;
		}
		if (jsval_promise_resolve(region, read_promise, done_result) < 0) {
			return -1;
		}
	}

	if (jsval_promise_resolve(region, promise, jsval_undefined()) < 0) {
		return -1;
	}
	*promise_ptr = promise;
	return 0;
}

static int jsval_readable_stream_run_pump(jsval_region_t *region,
		jsval_native_microtask_readable_stream_pump_t *task)
{
	jsval_off_t stream_off;
	jsval_native_readable_stream_t *stream;
	jsval_native_body_source_t *source;
	uint8_t scratch[JSVAL_FETCH_BODY_DRAIN_BATCH];
	size_t n = 0;
	jsval_body_source_status_t status = JSVAL_BODY_SOURCE_STATUS_ERROR;
	int rc;

	if (region == NULL || task == NULL) {
		errno = EINVAL;
		return -1;
	}
	stream_off = task->stream_off;
	stream = jsval_native_readable_stream_off(region, stream_off);
	if (stream == NULL) {
		errno = EINVAL;
		return -1;
	}
	stream->pump_scheduled = 0;

	if (stream->pending_reads_head == 0) {
		return 0;
	}
	if (stream->state != JSVAL_READABLE_STREAM_STATE_READABLE) {
		jsval_off_t read_off;
		while ((read_off = jsval_readable_stream_dequeue_read(region,
				stream)) != 0) {
			jsval_t p = jsval_promise_value(read_off);

			if (stream->state == JSVAL_READABLE_STREAM_STATE_ERRORED) {
				if (jsval_promise_reject(region, p,
						stream->error_reason) < 0) {
					return -1;
				}
			} else {
				jsval_t result;
				if (jsval_readable_stream_make_read_result(region, NULL,
						0, 1, &result) < 0) {
					return -1;
				}
				stream = jsval_native_readable_stream_off(region,
						stream_off);
				if (stream == NULL) {
					errno = EINVAL;
					return -1;
				}
				if (jsval_promise_resolve(region, p, result) < 0) {
					return -1;
				}
			}
		}
		return 0;
	}

	source = jsval_native_body_source(region, stream->source_off);
	if (source == NULL || source->vtable == NULL
			|| source->vtable->read == NULL) {
		errno = EINVAL;
		return -1;
	}
	rc = source->vtable->read(source->userdata, scratch, sizeof(scratch),
			&n, &status);
	if (rc < 0 || status == JSVAL_BODY_SOURCE_STATUS_ERROR) {
		jsval_t reason;
		jsval_off_t read_off;

		if (jsval_dom_exception_new_utf8(region, "TypeError",
				"stream source error", &reason) < 0) {
			return -1;
		}
		stream = jsval_native_readable_stream_off(region, stream_off);
		if (stream == NULL) {
			errno = EINVAL;
			return -1;
		}
		stream->state = JSVAL_READABLE_STREAM_STATE_ERRORED;
		stream->error_reason = reason;
		while ((read_off = jsval_readable_stream_dequeue_read(region,
				stream)) != 0) {
			jsval_t p = jsval_promise_value(read_off);
			if (jsval_promise_reject(region, p, reason) < 0) {
				return -1;
			}
		}
		return 0;
	}

	if (status == JSVAL_BODY_SOURCE_STATUS_EOF) {
		jsval_off_t read_off;
		int first = 1;

		stream->state = JSVAL_READABLE_STREAM_STATE_CLOSED;
		jsval_body_source_close_once(source);
		while ((read_off = jsval_readable_stream_dequeue_read(region,
				stream)) != 0) {
			jsval_t p = jsval_promise_value(read_off);
			jsval_t result;

			/* EOF may carry a final chunk. Deliver the chunk to the
			 * oldest pending reader; subsequent readers get done:true. */
			if (first && n > 0) {
				if (jsval_readable_stream_make_read_result(region, scratch,
						n, 0, &result) < 0) {
					return -1;
				}
			} else {
				if (jsval_readable_stream_make_read_result(region, NULL, 0,
						1, &result) < 0) {
					return -1;
				}
			}
			first = 0;
			stream = jsval_native_readable_stream_off(region, stream_off);
			if (stream == NULL) {
				errno = EINVAL;
				return -1;
			}
			if (jsval_promise_resolve(region, p, result) < 0) {
				return -1;
			}
		}
		return 0;
	}

	if (status == JSVAL_BODY_SOURCE_STATUS_PENDING || n == 0) {
		/* Park on source instead of re-enqueuing the pump. The
		 * producer will call jsval_body_source_notify after it
		 * pushes more data (or flags EOF/ERROR), which will
		 * schedule a fresh pump microtask for this stream. */
		source->parked_stream_off = stream_off;
		return 0;
	}

	{
		jsval_off_t read_off;
		jsval_t result;
		jsval_t p;

		read_off = jsval_readable_stream_dequeue_read(region, stream);
		if (read_off == 0) {
			errno = EINVAL;
			return -1;
		}
		if (jsval_readable_stream_make_read_result(region, scratch, n, 0,
				&result) < 0) {
			return -1;
		}
		p = jsval_promise_value(read_off);
		if (jsval_promise_resolve(region, p, result) < 0) {
			return -1;
		}
		stream = jsval_native_readable_stream_off(region, stream_off);
		if (stream != NULL && stream->pending_reads_head != 0) {
			return jsval_readable_stream_schedule_pump(region, stream_off);
		}
	}
	return 0;
}
